#include <stdio.h>
#include <stdint.h>
const long long MOD = 998244353LL;
const long long INV4 = 748683265LL; // modular inverse of 4 modulo MOD
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long n = N % MOD;
        long long np1 = (N + 1) % MOD;
        long long ans = n * np1 % MOD * np1 % MOD * INV4 % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

